int main() {
    int T, N, K, c, i, R;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &K);
        int A[N], sum = 0;
        for (i = 0; i < N; i++) {
            scanf("%d", &A[i]);
            sum += A[i];
        }
        R = sum % K;
        for (c = 0; c < N; c++) {
            int rem = sum - A[c];
            if (rem % K < R) {
                R = rem % K;
            }
        }
        printf("%d\n", R);
    }
    return 0;
}

