code.Java:
public class Main {
    public static void main(String[] args) {
        java.util.Scanner sc = new java.util.Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt(), K = sc.nextInt();
            int A[] = new int[N];
            int sum = 0;
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
                sum += A[i];
            }
            int R = sum % K;
            for (int c = 0; c < N; c++) {
                int rem = sum - A[c];
                if (rem % K < R) {
                    R = rem % K;
                }
            }
            System.out.println(R);
        }
    }
}

